"use client";
import { useState, useEffect } from 'react';
import { Users, UserPlus, ArrowRight } from 'lucide-react';

export default function ReceptionistDashboard() {
  const [patientName, setPatientName] = useState('');
  const [activeToken, setActiveToken] = useState(null);
  const clinicId = "clinic_123"; 
  
  // State for the room selector
  const [myRoom, setMyRoom] = useState('Room 1');

  useEffect(() => {
    const handleKeyDown = async (e) => {
      if (e.code === 'Space' && e.target.tagName !== 'INPUT') {
        e.preventDefault();
        callNextPatient();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [myRoom]); // Added myRoom to dependency array so the spacebar uses the correct room

  const addPatient = async (e) => {
    e.preventDefault();
    if (!patientName.trim()) return;
    
    await fetch('http://localhost:5000/api/queue/add', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ clinicId, patientName })
    });
    setPatientName(''); 
  };

  const callNextPatient = async () => {
    const res = await fetch('http://localhost:5000/api/queue/next', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      // WE NOW PASS THE SELECTED ROOM TO THE BACKEND
      body: JSON.stringify({ clinicId, roomNumber: myRoom }) 
    });
    const data = await res.json();
    if (data.activeToken) setActiveToken(data.activeToken.tokenNumber);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 text-slate-800">
      <div className="w-full max-w-4xl grid grid-cols-1 md:grid-cols-2 gap-8">
        
        {/* Left Column: Command Bar */}
        <div className="bg-white/70 backdrop-blur-xl border border-white/50 shadow-sm rounded-3xl p-8 flex flex-col justify-center">
          <h1 className="text-2xl font-semibold mb-6 flex items-center gap-2">
            <UserPlus className="text-blue-500" /> Queue Entry
          </h1>
          <form onSubmit={addPatient} className="flex flex-col gap-4">
            <input 
              type="text" 
              autoFocus
              placeholder="Type patient name & hit Enter..." 
              value={patientName}
              onChange={(e) => setPatientName(e.target.value)}
              className="w-full px-5 py-4 bg-white/50 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-blue-400 transition-all text-lg"
            />
          </form>
          <p className="text-xs text-slate-400 mt-4 font-medium tracking-wide uppercase">Sub-3 Second Workflow Enabled</p>
        </div>

        {/* Right Column: Execution Control */}
        <div className="bg-gradient-to-br from-blue-500 to-indigo-600 shadow-xl rounded-3xl p-8 text-white flex flex-col items-center justify-center relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10">
            <Users size={120} />
          </div>
          <h2 className="text-lg font-medium text-blue-100 mb-2">Currently Serving</h2>
          <div className="text-8xl font-bold tracking-tighter mb-8">
            {activeToken ? `#${activeToken}` : '--'}
          </div>

          {/* NEW ROOM SELECTOR DROPDOWN */}
          <div className="w-full mb-4 z-10 relative">
            <select 
              value={myRoom} 
              onChange={(e) => setMyRoom(e.target.value)}
              className="w-full bg-white/10 border border-white/20 text-white rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-white/50 appearance-none text-center font-medium shadow-inner backdrop-blur-sm cursor-pointer"
            >
              <option value="Room 1" className="text-slate-800 font-medium">Assign to Doctor A (Room 1)</option>
              <option value="Room 2" className="text-slate-800 font-medium">Assign to Doctor B (Room 2)</option>
              <option value="Room 3" className="text-slate-800 font-medium">Assign to Doctor C (Room 3)</option>
            </select>
          </div>

          <button 
            onClick={callNextPatient}
            className="group w-full bg-white text-blue-600 hover:bg-blue-50 font-semibold text-xl py-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 z-10"
          >
            Call Next <ArrowRight className="group-hover:translate-x-1 transition-transform" />
          </button>
          <p className="mt-4 text-blue-200 text-sm z-10">Or press <kbd className="bg-blue-800/30 px-2 py-1 rounded text-white font-mono text-xs">Spacebar</kbd></p>
        </div>

      </div>
    </div>
  );
}